/**
 * Webpack loader: replaces sp-* with xe-* in source so devs write standard SWC names.
 * Only applies to blocks/, utils/, styles/, scripts/ - not init.js or xe-*.js.
 *
 * Reads xe-components.tags.cjs (generated by prebuild). Falls back to xe-components.config.cjs if tags file missing.
 */
import path from 'path';
import { fileURLToPath } from 'url';
import { createRequire } from 'module';

const require = createRequire(import.meta.url);
const __dirname = path.dirname(fileURLToPath(import.meta.url));

export default function xeReplaceLoader(source) {
  const root = path.resolve(__dirname, '..');

  // Prefer tags file (generated by prebuild). Fall back to config keys.
  let tags = [];
  const tagsPath = path.join(root, 'xe-components.tags.cjs');
  try {
    tags = require(tagsPath);
  } catch {
    const configPath = path.join(root, 'xe-components.config.cjs');
    try {
      const config = require(configPath);
      const resolved = config?.default || config;
      tags = resolved && typeof resolved === 'object' ? Object.keys(resolved) : [];
    } catch {
      return source;
    }
  }

  if (!Array.isArray(tags) || tags.length === 0) return source;

  let result = source;
  for (const spTag of tags) {
    if (typeof spTag !== 'string' || !spTag.startsWith('sp-')) continue;
    const xeTag = spTag.replace('sp-', 'xe-');
    const regex = new RegExp(spTag.replace(/-/g, '\\-'), 'g');
    result = result.replace(regex, xeTag);
  }
  return result;
}
